args.sparql:
SELECT DISTINCT ?ruler ?rulerLabel ?startDate WHERE {
  { wd:Q1016 p:P1344 ?statement . ?statement ps:P1344 ?ruler . ?statement pq:P580 ?startDate }
  UNION
  { wd:Q1016 p:P35 ?statement . ?statement ps:P35 ?ruler . ?statement pq:P580 ?startDate }
  ?ruler rdfs:label ?rulerLabel .
  FILTER(lang(?rulerLabel) = 'en') .
  FILTER(?startDate >= "1951-12-24T00:00:00Z"^^xsd:dateTime)
} ORDER BY ?startDate
